// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Select,
  Checkbox,
  Toggle,
  RadioGroup,
  Slider,
  Badge,
  Spinner,
  Avatar,
  Alert,
  Progress,
  Image,
  Icon,
  Link,
  Tooltip,
  Table,
  Tabs,
  Toast,
  Accordion,
} from '@ggui-ai/design/primitives';
import {
  SearchField,
  FormField,
  MenuItem,
  Tag,
  Dropdown,
  Autocomplete,
  Breadcrumb,
  Pagination,
} from '@ggui-ai/design/components';
import {
  Header,
  Sidebar,
  CardGrid,
  CommentThread,
  DataTable,
  ChatWindow,
  NavigationBar,
  FileUploader,
  UserProfileCard,
  NotificationCenter,
  Modal,
  CommandPalette,
  Footer,
  Hero,
} from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
};

// ── TYPES: define local types and interfaces here ──
type SurveyAnswers = {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
};
// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');

  // ── STATE: define useState hooks here ──
  const [currentStep, setCurrentStep] = useState(1);
  const [answers, setAnswers] = useState<SurveyAnswers>({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: '',
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');

  // ── CALLBACKS: define useCallback for event handlers ──
  const validateEmail = useCallback((email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(email);
  }, []);

  const validateStep = useCallback(
    (step: number): boolean => {
      const newErrors: Record<string, string> = {};
      if (step === 1) {
        if (!answers.name.trim()) newErrors.name = 'Name is required';
        if (!answers.email.trim()) newErrors.email = 'Email is required';
        else if (!validateEmail(answers.email))
          newErrors.email = 'Invalid email format';
      } else if (step === 2) {
        if (answers.satisfaction === 0 || answers.satisfaction < 1)
          newErrors.satisfaction = 'Please select a satisfaction rating';
      }
      setErrors(newErrors);
      return Object.keys(newErrors).length === 0;
    },
    [answers, validateEmail],
  );

  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
       if (currentStep < 4) {
        setCurrentStep(currentStep + 1);
        setSubmitError('');
      }
    }
  }, [currentStep, validateStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setSubmitError('');
    }
  }, [currentStep]);

  const handleSubmit = useCallback(async () => {
    setIsSubmitting(true);
    setSubmitError('');
    try {
      submit(answers);
    } catch (err) {
      setSubmitError('Failed to submit survey. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  }, [answers, submit]);

  const updateAnswer = useCallback(
    (key: keyof SurveyAnswers, value: unknown) => {
      setAnswers((prev) => ({ ...prev, [key]: value }));
      setErrors((prev) => ({ ...prev, [key]: '' }));
    },
    [],
  );

  return {
    currentStep,
    answers,
    errors,
    isSubmitting,
    submitError,
    handleNext,
    handleBack,
    handleSubmit,
    updateAnswer,
    validateEmail,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container
      maxWidth="xl"
      padding={24}
    >
      <Stack gap={16}>
        <Stack gap={8}>
          <Heading level={1}>Survey</Heading>
          <Text variant="body">
            Please complete all steps to submit your survey
          </Text>
        </Stack>

        {/* PROGRESS */}
        {/* PROGRESS BAR */}
        <Progress
          value={state.currentStep}
          max={5}
          size="md"
        />
        <Text variant="label">Step {state.currentStep} of 5{state.currentStep === 5 ? ' (Review)' : ''}</Text>

        {/* CONTENT */}
        <Card
          padding={24}
          shadow="md"
        >
          <Stack gap={16}>
            {/* STEP 1: Name & Email */}
            {state.currentStep === 1 && (
              <Stack gap={12}>
                <Heading level={3}>Contact Information</Heading>
                <Input
                  label="Name"
                  required
                  value={state.answers.name}
                  onChange={(val) => state.updateAnswer('name', val)}
                  error={state.errors.name}
                  placeholder="Enter your full name"
                />
                <Input
                  label="Email"
                  required
                  type="email"
                  value={state.answers.email}
                  onChange={(val) => state.updateAnswer('email', val)}
                  error={state.errors.email}
                  placeholder="your@email.com"
                />
              </Stack>
            )}

            {/* STEP 2: Satisfaction Rating */}
            {state.currentStep === 2 && (
              <Stack gap={12}>
                <Heading level={3}>Overall Satisfaction</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={String(state.answers.satisfaction)}
                  onChange={(val) =>
                    state.updateAnswer('satisfaction', parseInt(val))
                  }
                 <RadioGroup
                   label="How satisfied are you?"
                   value={String(state.answers.satisfaction)}
                   onChange={(val) =>
                     state.updateAnswer('satisfaction', parseInt(val))
                   }
                   options={(props.satisfactionLabels ?? []).map((label, idx) => ({
                     value: String(idx + 1),
                     label,
                   }))}
                   direction="vertical"
                 />
            )}

            {/* STEP 3: Feature Interests */}
            {state.currentStep === 3 && (
              <Stack gap={12}>
                <Heading level={3}>Features of Interest</Heading>
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Select any features that interest you
                </Text>
                <Stack gap={8}>
                  {(props.featureOptions ?? []).map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.answers.features.includes(feature)}
                      onChange={(checked) => {
                        const updated = checked
                          ? [...state.answers.features, feature]
                          : state.answers.features.filter((f) => f !== feature);
                        state.updateAnswer('features', updated);
                      }}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* STEP 4: Comments */}
            {/* STEP 4: Comments */}
            {state.currentStep === 4 && (
              <Stack gap={12}>
                <Heading level={3}>Additional Comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={state.answers.comments}
                  onChange={(val) =>
                    state.updateAnswer('comments', val.slice(0, 500))
                  }
                  placeholder="Share any additional feedback..."
                  rows={6}
                  maxLength={500}
                  showCount
                />
              </Stack>
            )}

            {/* STEP 5: Review */}
            {state.currentStep === 5 && (
              <Stack gap={12}>
                <Heading level={3}>Review Your Answers</Heading>
                <Stack gap={16}>
                  <Box
                    paddingY={12}
                    paddingX={12}
                    borderRadius={8}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                  >
                    <Stack gap={8}>
                      <Text variant="label">Name</Text>
                      <Text>{state.answers.name}</Text>
                    </Stack>
                  </Box>
                  <Box
                    paddingY={12}
                    paddingX={12}
                    borderRadius={8}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                  >
                    <Stack gap={8}>
                      <Text variant="label">Email</Text>
                      <Text>{state.answers.email}</Text>
                    </Stack>
                  </Box>
                  <Box
                    paddingY={12}
                    paddingX={12}
                    borderRadius={8}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                  >
                    <Stack gap={8}>
                      <Text variant="label">Satisfaction Rating</Text>
                       <Text>
                         {state.answers.satisfaction > 0
                           ? props.satisfactionLabels?.[
                               state.answers.satisfaction - 1
                             ] || 'Not selected'
                           : 'Not selected'}
                       </Text>
                  </Box>
                  <Box
                    paddingY={12}
                    paddingX={12}
                    borderRadius={8}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                  >
                    <Stack gap={8}>
                      <Text variant="label">Features</Text>
                      <Text>
                        {state.answers.features.length > 0
                          ? state.answers.features.join(', ')
                          : 'None selected'}
                      </Text>
                    </Stack>
                  </Box>
                  <Box
                    paddingY={12}
                    paddingX={12}
                    borderRadius={8}
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                  >
                    <Stack gap={8}>
                      <Text variant="label">Comments</Text>
                      <Text>{state.answers.comments || '(empty)'}</Text>
                    </Stack>
                  </Box>
                </Stack>
              </Stack>
            )}
          </Stack>
        </Card>

        {state.submitError && (
          <Alert
            variant="error"
            title="Submission Error"
          >
            {state.submitError}
          </Alert>
        )}

        {/* FOOTER / ACTIONS */}
        <Row
          gap={8}
          justify="between"
        >
          <Button
            variant="secondary"
            onClick={() => state.handleBack()}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
           {state.currentStep < 5 ? (
             <Button
               variant="primary"
               onClick={() => state.handleNext()}
               disabled={Object.keys(state.errors).length > 0}
             >
               Next
             </Button>
           ) : (
             <Button
               variant="primary"
               onClick={() => state.handleSubmit()}
               loading={state.isSubmitting}
             >
               Submit
             </Button>
           )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Divider,
  Spacer,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  Select,
  Checkbox,
  Toggle,
  RadioGroup,
  Slider,
  Badge,
  Spinner,
  Avatar,
  Alert,
  Progress,
  Image,
  Icon,
  Link,
  Tooltip,
  Table,
  Tabs,
  Toast,
  Accordion,
} from '@ggui-ai/design/primitives';
import {
  SearchField,
  FormField,
  MenuItem,
  Tag,
  Dropdown,
  Autocomplete,
  Breadcrumb,
  Pagination,
} from '@ggui-ai/design/components';
import {
  Header,
  Sidebar,
  CardGrid,
  CommentThread,
  DataTable,
  ChatWindow,
  NavigationBar,
  FileUploader,
  UserProfileCard,
  NotificationCenter,
  Modal,
  CommandPalette,
  Footer,
  Hero,
} from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';

// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = {
  action: string;
  taskId: string;
  data: { column: string };
};

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = {
  action?: 'create' | 'move' | 'edit' | 'delete';
  task?: {
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  };
};

// ── TYPES: define local types and interfaces here ──
interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: string;
  column: string;
  dueDate?: string;
}

// ── CONSTANTS: define constants, config, mappings here ──
const PRIORITY_COLORS: Record<'low' | 'medium' | 'high', string> = {
  low: 'var(--ggui-color-success-100, #dcfce7)',
  medium: 'var(--ggui-color-warning-100, #fef3c7)',
  high: 'var(--ggui-color-error-100, #fee2e2)',
};

const PRIORITY_VARIANTS: Record<
  'low' | 'medium' | 'high',
  'success' | 'warning' | 'error'
> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};
// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // STATE: define useState hooks here
  const [tasks, setTasks] = useState<Task[]>(
    props.tasks?.map(
      (t) =>
        ({ ...t, id: t.id || `task-${Date.now()}-${Math.random()}` }) as Task,
    ) || [],
  );
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<
    'low' | 'medium' | 'high'
  >('medium');

  // Sync stream updates into local tasks
  React.useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task?.id) return;
      setTasks((prev) => {
        if (action === 'create') return [...prev, { ...task } as Task];
        if (action === 'delete') return prev.filter((t) => t.id !== task.id);
        return prev.map((t) => (t.id === task.id ? { ...t, ...task } : t));
      });
    }
  }, [taskChanged.latest]);

  // CALLBACKS: define useCallback for event handlers
  const handleMoveTask = useCallback(
    (taskId: string, targetColumn: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t)),
      );
      taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
    },
    [taskUpdate],
  );

  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const newId = `task-${Date.now()}-${Math.random()}`;
      const newTask: Task = {
        id: newId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId: newId,
        data: {
          column: columnId,
          title: newTaskTitle,
          priority: newTaskPriority,
        },
      } as any);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate],
  );

  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      if (!newTitle.trim()) return;
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t)),
      );
      taskUpdate({
        action: 'edit',
        taskId,
        data: { title: newTitle } as any,
      });
      setEditingTaskId(null);
      setEditingTitle('');
    },
    [taskUpdate],
  );

  return {
    tasks,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    addingColumnId,
    setAddingColumnId,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    handleMoveTask,
    handleAddTask,
    handleEditTask,
  };
}

export default function Component(props: Props) {
  const {
    tasks,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    addingColumnId,
    setAddingColumnId,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    handleMoveTask,
    handleAddTask,
    handleEditTask,
  } = useComponent(props);

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  return (
    <Container
      maxWidth="2xl"
      padding={24}
    >
      <Stack gap={24}>
        {/* SUMMARY BAR */}
        <Box
          background="var(--ggui-color-primary-50, #f0f9ff)"
          padding={16}
          borderRadius="var(--ggui-shape-radius-md, 8px)"
        >
          <Row
            gap={32}
            justify="start"
          >
            <Stack
              gap={4}
              align="center"
            >
              <Text
                variant="label"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Total Tasks
              </Text>
              <Heading
                level={3}
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {totalTasks}
              </Heading>
            </Stack>
            <Stack
              gap={4}
              align="center"
            >
              <Text
                variant="label"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Completed
              </Text>
              <Heading
                level={3}
                color="var(--ggui-color-success-600, #16a34a)"
              >
                {completedTasks}
              </Heading>
            </Stack>
          </Row>
        </Box>

        {/* KANBAN BOARD */}
        <Row
          gap={16}
          align="start"
          wrap
        >
          {(props.columns || []).map((col) => {
            const colTasks = tasks.filter((t) => t.column === col.id);
            return (
              <Box
                key={col.id}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                padding={16}
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                style={{ minWidth: '300px', flex: '0 0 300px' }}
              >
                <Stack gap={12}>
                  {/* COLUMN HEADER */}
                  <Row
                    gap={8}
                    justify="between"
                    align="center"
                  >
                    <Heading level={4}>{col.name || 'Unnamed Column'}</Heading>
                    <Badge
                      variant="info"
                      size="sm"
                      pill
                    >
                      {colTasks.length}
                    </Badge>
                  </Row>

                  <Divider margin={0} />

                  {/* TASK CARDS */}
                  <Stack gap={8}>
                    {colTasks.map((task) => (
                      <Card
                        key={task.id}
                        shadow="sm"
                        padding={12}
                        radius="md"
                        border
                      >
                        <Stack gap={8}>
                          {/* TITLE & EDIT BUTTON */}
                          <Row
                            gap={8}
                            align="center"
                            justify="between"
                          >
                            {editingTaskId === task.id ? (
                              <Stack
                                gap={8}
                                style={{ flex: 1 }}
                              >
                                <Input
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                  label=""
                                  onKeyDown={(e) => {
                                    if (e.key === 'Enter') {
                                      handleEditTask(task.id, editingTitle);
                                    } else if (e.key === 'Escape') {
                                      setEditingTaskId(null);
                                      setEditingTitle('');
                                    }
                                  }}
                                />
                                <Row gap={8}>
                                  <Button
                                    variant="primary"
                                    size="xs"
                                    fullWidth
                                    onClick={() =>
                                      handleEditTask(task.id, editingTitle)
                                    }
                                  >
                                    Save
                                  </Button>
                                  <Button
                                    variant="ghost"
                                    size="xs"
                                    fullWidth
                                    onClick={() => {
                                      setEditingTaskId(null);
                                      setEditingTitle('');
                                    }}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              </Stack>
                            ) : (
                              <>
                                <Text
                                  variant="body"
                                  weight="medium"
                                  style={{ flex: 1, cursor: 'pointer' }}
                                  onDoubleClick={() => {
                                    setEditingTaskId(task.id);
                                    setEditingTitle(task.title);
                                  }}
                                >
                                  {task.title}
                                </Text>
                                <Button
                                  variant="ghost"
                                  size="xs"
                                  leftIcon={
                                    <Icon
                                      name="edit"
                                      size={14}
                                    />
                                  }
                                  onClick={() => {
                                    setEditingTaskId(task.id);
                                    setEditingTitle(task.title);
                                  }}
                                />
                              </>
                            )}
                          </Row>

                          {/* PRIORITY BADGE */}
                          <Badge
                            variant={PRIORITY_VARIANTS[task.priority]}
                            size="sm"
                            pill
                            style={{
                              backgroundColor: PRIORITY_COLORS[task.priority],
                            }}
                          >
                            {task.priority}
                          </Badge>

                          {/* DUE DATE */}
                          {task.dueDate && (
                            <Text
                              variant="caption"
                              color="var(--ggui-color-onSurfaceVariant, #52525b)"
                            >
                              Due: {new Date(task.dueDate).toLocaleDateString()}
                            </Text>
                          )}

                          {/* ASSIGNEE */}
                          {task.assignee && (
                            <Avatar
                              name={task.assignee}
                              size="sm"
                            />
                          )}

                          {/* MOVE DROPDOWN */}
                          {props.columns.length > 1 && (
                            <Dropdown
                              trigger={
                                <Button
                                  variant="outline"
                                  size="xs"
                                  fullWidth
                                  leftIcon={
                                    <Icon
                                      name="arrow-right"
                                      size={14}
                                    />
                                  }
                                >
                                  Move
                                </Button>
                              }
                              options={(props.columns || [])
                                .filter((c) => c.id !== col.id)
                                .map((c) => ({
                                  value: c.id || '',
                                  label: c.name || 'Unknown',
                                }))}
                              value={task.column}
                              onChange={(target) =>
                                handleMoveTask(task.id, target)
                              }
                            />
                          )}
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* ADD TASK BUTTON / FORM */}
                  {addingColumnId === col.id ? (
                    <Card
                      shadow="sm"
                      padding={12}
                      radius="md"
                      border
                    >
