    null,
  );
  const [expandedCategories, setExpandedCategories] = useState<string[]>([]);

  // ── MEMOS: define useMemo for derived/computed values ──
  const filteredElements = useMemo(() => {
    const query = searchQuery.toLowerCase();
    return props.elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(query) ||
        false ||
        e.symbol?.toLowerCase().includes(query) ||
        false,
    );
  }, [props.elements, searchQuery]);

  const uniqueCategories = useMemo(() => {
    return Array.from(
      new Set(props.elements.map((e) => e.category).filter(Boolean)),
    );
  }, [props.elements]);

  // ── CALLBACKS: define useCallback for event handlers ──
  const handleElementClick = useCallback((element: Props['elements'][0]) => {
