/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

// ── TYPES: define local types and interfaces here ──

// ── CONSTANTS: define constants, config, mappings here ──

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  // STATE: define useState hooks here
  const [selectedTab, setSelectedTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);

  // CALLBACKS: define useCallback for event handlers
  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  const handleQuantityChange = useCallback(
    (newQty: number) => {
      const maxQty = props.product.stock ?? 1;
      setQuantity(Math.max(1, Math.min(newQty, maxQty)));
    },
    [props.product.stock],
  );

  return {
    selectedTab,
    setSelectedTab,
    quantity,
    handleQuantityChange,
    handleAddToCart,
  };
}

