      sendMessage({ text: inputValue, timestamp: new Date().toISOString() });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage],
  );

  // Handle incoming messages from stream
  React.useEffect(() => {
    if (message.latest) {
      setMessageList((prev) => [...prev, message.latest!]);
      messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [message.latest]);

  // Handle typing indicator
  React.useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || null);
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);
  return {
    sendMessage,
    message,
    typing,
    messageList,
    inputValue,
    setInputValue,
    typingUser,
    handleSendMessage,
    handleKeyDown,
    messagesEndRef,
  };
}
