// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = {
  symbol?: string;
  price?: number;
  change?: number;
  changePercent?: number;
};

/** Stream event: Market open/closed status update */
type StreamMarketStatus = {
  status?: 'open' | 'closed' | 'pre-market' | 'after-hours';
  timestamp?: string;
};

// ── TYPES: define local types and interfaces here ──
interface StockData {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
  isFlashing?: boolean;
}

// ── CONSTANTS: define constants, config, mappings here ──

function useComponent(props: Props) {
  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // ── STATE: define useState hooks here ──
  const [stocks, setStocks] = useState<StockData[]>(() =>
    (props.stocks || []).map((s) => ({
      symbol: s.symbol || '',
      name: s.name || '',
      price: s.price || 0,
      change: s.change || 0,
      changePercent: s.changePercent || 0,
      isFlashing: false,
    }))
  );
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());

  // ── MEMOS: define useMemo for derived/computed values ──

  // ── CALLBACKS: define useCallback for event handlers ──
  const handlePriceUpdate = useCallback(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prev) =>
        prev.map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
              isFlashing: true,
            };
          }
          return stock;
        })
      );
      setLastUpdated(new Date());

      // Clear flash animation after 600ms
      const timer = setTimeout(() => {
        setStocks((prev) =>
          prev.map((s) => ({ ...s, isFlashing: false }))
        );
      }, 600);
      return () => clearTimeout(timer);
    }
  }, [priceUpdate.latest]);

  React.useEffect(() => {
    handlePriceUpdate();
  }, [priceUpdate.latest, handlePriceUpdate]);

  return { stocks, lastUpdated, marketStatus };
}
}

