// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
};

// ── TYPES: define local types and interfaces here ──
type StepKey = 'profile' | 'preferences' | 'review';

// ── SUB-COMPONENTS: extract reusable UI pieces as small functions (<30 lines each) ──

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // ── STATE: define useState hooks here ──
  const [currentStep, setCurrentStep] = useState<StepKey>('profile');
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(
    props.initialProfile.avatar || props.avatarOptions[0] || '',
  );
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(
    props.initialProfile.emailNotifications !== false,
  );
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // ── CALLBACKS: define useCallback for event handlers ──
  const validateEmail = useCallback((value: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
  }, []);

  const isStep1Valid = useCallback((): boolean => {
    return (
      name.trim().length > 0 &&
      email.trim().length > 0 &&
      validateEmail(email) &&
      avatar.length > 0
    );
  }, [name, email, validateEmail, avatar]);

  const isStep2Valid = useCallback((): boolean => {
    return role.trim().length > 0;
  }, [role]);

  const handleNext = useCallback(() => {
    if (currentStep === 'profile') {
      if (isStep1Valid()) {
        setCurrentStep('preferences');
      }
    } else if (currentStep === 'preferences') {
      if (isStep2Valid()) {
        setCurrentStep('review');
      }
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep === 'preferences') {
      setCurrentStep('profile');
    } else if (currentStep === 'review') {
      setCurrentStep('preferences');
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [complete, name, email, avatar, role, emailNotifications, theme]);

  const stepIndex =
    currentStep === 'profile' ? 0 : currentStep === 'preferences' ? 1 : 2;
  const totalSteps = 3;

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    avatar,
    setAvatar,
    role,
    setRole,
    emailNotifications,
    setEmailNotifications,
    theme,
    setTheme,
    isStep1Valid,
    isStep2Valid,
    handleNext,
    handleBack,
    handleComplete,
    stepIndex,
    totalSteps,
    validateEmail,
  };
}

